package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class GsonBuilderTest {

  private GsonBuilder gsonBuilder;
  private Excluder excluderMock;

  @BeforeEach
  public void setUp() throws Exception {
    gsonBuilder = new GsonBuilder();

    // Use reflection to set private excluder field to a mock
    excluderMock = mock(Excluder.class);
    when(excluderMock.withVersion(anyDouble())).thenReturn(excluderMock);

    Field excluderField = GsonBuilder.class.getDeclaredField("excluder");
    excluderField.setAccessible(true);
    excluderField.set(gsonBuilder, excluderMock);
  }

  @Test
  public void testSetVersion_validVersion() {
    double version = 1.5;

    GsonBuilder returned = gsonBuilder.setVersion(version);

    assertSame(gsonBuilder, returned, "setVersion should return the same GsonBuilder instance");
    verify(excluderMock).withVersion(version);
  }

  @Test
  public void testSetVersion_zeroVersion() {
    double version = 0.0;

    GsonBuilder returned = gsonBuilder.setVersion(version);

    assertSame(gsonBuilder, returned, "setVersion should return the same GsonBuilder instance");
    verify(excluderMock).withVersion(version);
  }

  @Test
  public void testSetVersion_negativeVersion_throwsException() {
    double version = -0.1;

    IllegalArgumentException thrown = assertThrows(IllegalArgumentException.class, () -> {
      gsonBuilder.setVersion(version);
    });
    assertEquals("Invalid version: " + version, thrown.getMessage());
    verify(excluderMock, never()).withVersion(anyDouble());
  }

  @Test
  public void testSetVersion_NaNVersion_throwsException() {
    double version = Double.NaN;

    IllegalArgumentException thrown = assertThrows(IllegalArgumentException.class, () -> {
      gsonBuilder.setVersion(version);
    });
    assertEquals("Invalid version: " + version, thrown.getMessage());
    verify(excluderMock, never()).withVersion(anyDouble());
  }
}
